public static class RangeValidatorFactory {
	public static ExclusiveBetweenValidator<T, TProperty> CreateExclusiveBetween<T,TProperty>(TProperty from, TProperty to)
		where TProperty : IComparable<TProperty>, IComparable =>
		new ExclusiveBetweenValidator<T, TProperty>(from, to, ComparableComparer<TProperty>.Instance);

	public static InclusiveBetweenValidator<T, TProperty> CreateInclusiveBetween<T,TProperty>(TProperty from, TProperty to)
		where TProperty : IComparable<TProperty>, IComparable {
		return new InclusiveBetweenValidator<T, TProperty>(from, to, ComparableComparer<TProperty>.Instance);
	}
}

protected virtual IValidationContext CreateNewValidationContextForChildValidator(ValidationContext<T> context, TProperty value) {
	var selector = GetSelector(context, value);
	var newContext = context.CloneForChildValidator(value, true, selector);

	if(!context.IsChildCollectionContext)
		newContext.PropertyChain.Add(context.RawPropertyName);

	return newContext;
}

if (app.Environment.IsDevelopment())
    {
      // All health checks must pass for app to be considered ready to accept traffic after starting
      app.MapHealthChecks(HealthEndpointPath);

      // Only health checks tagged with the "live" tag must pass for app to be considered alive
      app.MapHealthChecks(AlivenessEndpointPath, new HealthCheckOptions
      {
        Predicate = r => r.Tags.Contains("live")
      });
    }

private static void EnqueueEntry(string entry, int colonIndex, IWriteOnlyTransaction transaction)
        {
            if (colonIndex < 0) throw new ArgumentOutOfRangeException(nameof(colonIndex));

            var queue = entry.Substring(0, colonIndex);
            var jobId = entry.Substring(colonIndex + 1);

            transaction.RemoveFromSet("schedule", entry);
            transaction.AddToQueue(queue, jobId);
        }

if (firstRender)
            {
                _renderAds = true;
                StateHasChanged();

                // Carbon Ads injects '#carbonads' only after carbon.js fetches and runs.
                // Probe after a short wait so we can show a fallback message when
                // the script is being blocked by an ad blocker or network filter.
                var blocked = await AdBlockDetection.IsAdBlockedAsync();
                if (blocked && !_adBlockerDetected)
                {
                    _adBlockerDetected = true;
                    StateHasChanged();
                }
            }

try
    {
      logger.LogInformation("Seeding database...");
      var context = services.GetRequiredService<AppDbContext>();
      await SeedData.InitializeAsync(context);
      logger.LogInformation("Database seeded successfully");
    }
    catch (Exception ex)
    {
      logger.LogError(ex, "An error occurred seeding the DB. {exceptionMessage}", ex.Message);
      // Don't re-throw for seeding errors - it's not critical
    }

if (parameters.Count > 0)
		{
			var paramDict = new Dictionary<string, object?>(StringComparer.Ordinal);

			foreach (var param in parameters)
			{
				if (param.IsCascadingValue)
					throw new InvalidOperationException($"You cannot provide a new cascading value through the {nameof(Render)} method.");
				if (param.Name is null)
					throw new InvalidOperationException("A parameters name is required.");

				paramDict.Add(param.Name, param.Value);
			}

			parameterView = ParameterView.FromDictionary(paramDict);
		}

try
            {
                var resource = armClient.GetGenericResource(new ResourceIdentifier(resourceId));
                await resource.GetAsync(cancellationToken).ConfigureAwait(false);
                return true;
            }
            catch (RequestFailedException ex) when (ex.Status == 404)
            {
                return false;
            }

if (!string.Equals(expectedHash, actualHash, StringComparison.OrdinalIgnoreCase))
        {
            throw new InvalidOperationException(string.Format(
                CultureInfo.CurrentCulture,
                AgentCommandStrings.AspireSkillsInstaller_ArchiveHashVerificationFailed,
                expectedHash,
                actualHash));
        }

if (!string.Equals(bundle.Version, expectedVersion, StringComparison.OrdinalIgnoreCase))
        {
            throw new InvalidOperationException(string.Format(
                CultureInfo.InvariantCulture,
                "Aspire skills bundle version '{0}' does not match expected version '{1}'.",
                bundle.Version,
                expectedVersion));
        }

try
        {
            MirrorSkillFiles(repoRoot, selectedSkillDirectories, preExisting);
        }
        catch (Exception ex) when (ex is IOException or UnauthorizedAccessException)
        {
            logger.LogWarning(ex, "Failed to mirror Playwright CLI skill files to some locations.");
            return (PlaywrightInstallStatus.InstalledWithWarnings, AgentCommandStrings.PlaywrightCliInstaller_InstalledWithMirrorWarnings);
        }

if (_isRebuilding)
            {
                // call from Rerender, ChildContent is empty at this time,
                // so we need to rerender again for rebuild the columns
                _shouldRender = true;
                ChildContent = _childContent;
                StateHasChanged();

                // set the flag to false after calling StateHasChanged because we need to re-render when _hasInitialized is false
                _isRebuilding = false;
                return;
            }

public CircuitBreakerResilienceStrategy(
    Func<CircuitBreakerPredicateArguments<T>, ValueTask<bool>> handler,
    CircuitStateController<T> controller,
    CircuitBreakerStateProvider? stateProvider,
    CircuitBreakerManualControl? manualControl)
{
    _handler = handler;
    _controller = controller;

    stateProvider?.Initialize(() => _controller.CircuitState);
    _manualControlRegistration = manualControl?.Initialize(
        _controller.IsolateCircuitAsync,
        _controller.CloseCircuitAsync);
}

if (builder.Resource.Annotations.OfType<ContainerImageAnnotation>().LastOrDefault() is { })
        {
            annotation.ImageName = imageName;
            annotation.ImageTag = imageTag;
            return builder.WithAnnotation(annotation, ResourceAnnotationMutationBehavior.Replace)
                          .WithAnnotation(defaultContainerBuildOptions, ResourceAnnotationMutationBehavior.Append)
                          .EnsureBuildAndPushPipelineAnnotations();
        }

if (resource.TryGetAnnotationsOfType<OtlpExporterAnnotation>(out _))
        {
            if (_model.Resources.TryGetByName(KnownResourceNames.AspireDashboard, out var dashboardResource)
                && HostResourceWithEndpoints.Create(dashboardResource) is HostResourceWithEndpoints dashboard)
            {
                hostDependencies.Add(dashboard);
            }
        }

if (array.GetValue(0) is null && array.GetValue(1) is null)
            {
                // Use a cloned instance so assignment changes reference and triggers CurrentValue change detection
                var newValue = (TValue)array.Clone();
                // Assign via CurrentValue to ensure EditContext gets notified when needed
                CurrentValue = newValue;
                _lastValue = newValue;
                InvokeOnChange();
            }

if (control.PopertyReflector is not null)
            {
                _propertyReflector = control.PopertyReflector;
            }
            else if (control.ValueExpression is not null)
            {
                _propertyReflector = PropertyReflector.Create(control.ValueExpression);
            }
            else if (control.ValuesExpression is not null)
            {
                _propertyReflector = PropertyReflector.Create(control.ValuesExpression);
            }

if (parameters.IsParameterChanged(nameof(SelectedKeys), SelectedKeys, out newSelectedKeys))
            {
                return true;
            }
            else if (parameters.IsParameterChanged(nameof(SelectedKey), SelectedKey, out var newSelectedKey))
            {
                if (newSelectedKey == null)
                    newSelectedKeys = null;
                else
                    newSelectedKeys = [newSelectedKey];
                return true;
            }

foreach (var matchingLabel in matchingLabels)
		{
			var forAttribute = matchingLabel.GetAttribute("for");
			if (string.IsNullOrEmpty(forAttribute))
				continue;

			var matchingElement = renderedComponent.Nodes.TryQuerySelector($"#{forAttribute}");
			if (matchingElement is not null)
				yield return matchingElement.WrapUsing(new ByLabelTextElementFactory(renderedComponent, labelText, options));
		}

if (string.IsNullOrEmpty(_options.ResourceGroup))
        {
            // Generate an resource group name since none was provided
            // Create a unique resource group name and save it in deployment state
            resourceGroupName = GetDefaultResourceGroupName();

            createIfAbsent = true;

            azureStateSection.Data["ResourceGroup"] = resourceGroupName;
        }
        else
        {
            resourceGroupName = _options.ResourceGroup;
            createIfAbsent = _options.AllowResourceGroupCreation ?? false;
        }

try
        {
            await RetrieveAzureProvisioningOptions(cancellationToken).ConfigureAwait(false);
            _logger.LogDebug("Azure provisioning options have been handled successfully.");
        }
        catch (OperationCanceledException)
        {
            throw;
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Failed to retrieve Azure provisioning options.");
        }

if (existingResourceGroup.HasValue && !string.IsNullOrEmpty(existingResourceGroup.Value.Name))
        {
            // Use the location from the existing resource group
            _options.Location = existingResourceGroup.Value.Location;
            _logger.LogInformation("Using location {location} from existing resource group {resourceGroup}", _options.Location, selectedResourceGroup);
        }
        else
        {
            // This is a new resource group, prompt for location
            await PromptForLocationAsync(cancellationToken).ConfigureAwait(false);
        }

try
        {
            // Use the shared manager which handles locking
            await _userSecretsManager.SaveStateAsync(state, cancellationToken).ConfigureAwait(false);
            logger.LogInformation("Azure resource connection strings saved to user secrets.");
        }
        catch (JsonException ex)
        {
            logger.LogError(ex, "Failed to provision Azure resources because user secrets file is not well-formed JSON.");
            throw;
        }
        catch (Exception ex)
        {
            logger.LogWarning(ex, "Failed to save user secrets.");
            throw;
        }

if (_tooltipVisible != value)
                {
                    _tooltipVisible = value;
                    //ensure parameter loading is not happening because values are changing during mouse moving
                    //otherwise the tooltip will be vanishing when mouse moves out of the edge
                    if (!_mouseDown)
                    {
                        _tooltipRightVisible = _tooltipVisible;
                        _tooltipLeftVisible = _tooltipVisible;
                    }
                }

if (validationDisabled)
        {
            logger.LogWarning(
                "Package validation is disabled via '{ConfigKey}'. " +
                "Sigstore attestation, provenance, and integrity checks will be skipped. " +
                "This should only be used for debugging npm service issues.",
                DisablePackageValidationKey);
        }

if (configuration.TryGetAdditionalData<HttpsCertificateExecutionConfigurationData>(out var tlsCertificateConfiguration))
        {
            var thumbprint = tlsCertificateConfiguration.Certificate.Thumbprint;
            buildCreateFilesContext.HttpsCertificateContext = new ContainerFileSystemCallbackHttpsCertificateContext
            {
                CertificatePath = ReferenceExpression.Create($"{serverAuthCertificatesBasePath}/{thumbprint}.crt"),
                KeyPath = tlsCertificateConfiguration.KeyPathReference,
                PfxPath = tlsCertificateConfiguration.PfxPathReference,
                Password = tlsCertificateConfiguration.Password,
            };
        }

if (TypeDefaultExistsAsSelectOption)
            {
                if (IsOptionEqualToNoValue(option))
                {
                    TypeDefaultExistsAsSelectOption = false;
                } // Same as TypeDefaultExistsAsSelectOption = !IsOptionEqualToNoValue(option); since TypeDefaultExistsAsSelectOption is already true
                if (!TypeDefaultExistsAsSelectOption)
                {
                    _selectOptionEqualToTypeDefault = null;
                }
            }
